// Components
import MovieCard from "./MovieCard";

function Collection({ movies }) {

    const renderCollection = movies.map(movie => {
        return (
            <MovieCard 
                key={movie.id}
                title= {movie.title}
                rating= {movie.rating}
                release= {movie.release}
                genre= {movie.genre}
                runtime= {movie.runtime}
                poster= {movie.poster}
                writer= {movie.writer}
                director= {movie.director}
                myRating= {movie.myRating}
                collection= {movie.collection}
            />
        )
    })

    return (
        <div className="p-10 grid grid-cols">
            {renderCollection}
        </div>
    )
}

export default Collection;
